  ('disabled-e3452428-moex-00345', 'disabled-e3452428', 'disabled-e3452428-moex-110-3082b5f1', 'sub-disabled-e3452428-05', NULL, 'single_choice', '關於行政處分之效力，下列敘述何者正確？', '["納稅義務人於法定救濟期間經過後不得對課稅處分提起行政爭訟，係因 課稅處分發生實質存續力", "公司違法，主管機關依法針對公司登記之負責人裁罰，係因公司登記之 處分對其發生構成要件效力", "勞工機關裁罰違法僱用外籍移工之公司，內政部移民署得基於該處分之 執行力而限期令該外籍移工出國", "社福機關對違法長期照護中心裁罰後拒不繳納，因該裁罰處分已具確認 效力，得直接移送行政執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:18+00:00", "source_pdf_sha1": "2f314779229e", "answer_pdf_sha1": "2390de2c8cd0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "一般民政"}'::jsonb, NULL),
